import{_ as e,o as l,c as i,a3 as r}from"./chunks/framework.BsQeBrPm.js";const b=JSON.parse('{"title":"軍事・戦闘ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"guide/military-guide.md","filePath":"guide/military-guide.md"}'),a={name:"guide/military-guide.md"},o={viewBox:"0 0 300 240",width:"300",height:"240",xmlns:"http://www.w3.org/2000/svg",style:{display:"block",margin:"1rem auto","font-family":"inherit"}};function d(n,t,s,h,g,u){return l(),i("div",null,[t[1]||(t[1]=r('<h1 id="軍事・戦闘ガイド" tabindex="-1">軍事・戦闘ガイド <a class="header-anchor" href="#軍事・戦闘ガイド" aria-label="Permalink to &quot;軍事・戦闘ガイド&quot;">​</a></h1><blockquote><p>このページはインターネット上の攻略情報を集約した内容です。未検証の情報を含む場合があります。</p></blockquote><hr><h2 id="戦闘の基本" tabindex="-1">戦闘の基本 <a class="header-anchor" href="#戦闘の基本" aria-label="Permalink to &quot;戦闘の基本&quot;">​</a></h2><ul><li>Anno 117 の戦闘は <strong>陸戦</strong> と <strong>海戦</strong> の2系統に分かれます。</li><li>戦闘の中心は <strong>総督のヴィラ</strong> を巡る攻防です。各島の防衛の要であり、敵の総督のヴィラを制圧するとその島全体を奪取できます。</li><li><strong>士気</strong> が重要システムです。HPとは別に管理する必要があり、戦闘中に士気が下がりすぎると部隊が<strong>敗走</strong>します。敗走した部隊は近くの味方の士気にも悪影響を与え、より大規模な総崩れに発展します。</li><li>陸戦ユニットは<strong>相性型</strong>で設計されています: <ul><li><strong>歩兵</strong>は騎兵に強い</li><li><strong>弓兵・投石兵</strong>（遠隔ユニット）は歩兵に強く、騎兵に弱い</li><li><strong>騎兵</strong>は遠隔ユニットに強く、歩兵に弱い</li><li><strong>攻城兵器</strong>は敵部隊を対象とした<strong>バリスタ</strong>と建物を対象とした<strong>カタパルト</strong>がある</li></ul></li></ul><p>ユニットの相性（三すくみ）:</p>',6)),(l(),i("svg",o,[...t[0]||(t[0]=[r('<defs><marker id="arr" markerWidth="8" markerHeight="8" refX="6" refY="3" orient="auto"><path d="M0,0 L0,6 L8,3 z" fill="#666"></path></marker></defs><line x1="168" y1="52" x2="222" y2="145" stroke="#666" stroke-width="1.5" marker-end="url(#arr)"></line><line x1="208" y1="168" x2="108" y2="168" stroke="#666" stroke-width="1.5" marker-end="url(#arr)"></line><line x1="78" y1="145" x2="132" y2="52" stroke="#666" stroke-width="1.5" marker-end="url(#arr)"></line><text x="210" y="108" font-size="11" fill="#555" text-anchor="middle">強い</text><text x="150" y="190" font-size="11" fill="#555" text-anchor="middle">強い</text><text x="90" y="108" font-size="11" fill="#555" text-anchor="middle">強い</text><rect x="110" y="20" width="80" height="36" rx="6" fill="#e8f0fe" stroke="#4a7fd4" stroke-width="1.5"></rect><text x="150" y="43" font-size="14" font-weight="bold" fill="#1a3a6b" text-anchor="middle">歩兵</text><rect x="210" y="150" width="80" height="36" rx="6" fill="#fce8e8" stroke="#d44a4a" stroke-width="1.5"></rect><text x="250" y="173" font-size="14" font-weight="bold" fill="#6b1a1a" text-anchor="middle">騎兵</text><rect x="10" y="150" width="80" height="36" rx="6" fill="#e8fce8" stroke="#4ad44a" stroke-width="1.5"></rect><text x="50" y="173" font-size="14" font-weight="bold" fill="#1a6b1a" text-anchor="middle">遠隔</text>',13)])])),t[2]||(t[2]=r('<h3 id="ユニット・艦船の操作・スタンス" tabindex="-1">ユニット・艦船の操作・スタンス <a class="header-anchor" href="#ユニット・艦船の操作・スタンス" aria-label="Permalink to &quot;ユニット・艦船の操作・スタンス&quot;">​</a></h3><ul><li>個別選択のほか、ドラッグで全部隊・全艦隊を一括選択できます。</li><li>攻撃は敵（対象）を選択して実行します。移動する敵を狙う際はゲームを一時停止すると照準しやすいです。</li><li>スタンスは陸・海ともに共通の3種: <ul><li><strong>積極</strong>: 敵が近づくと命令を放棄して攻撃する</li><li><strong>規律</strong>: 命令を決して放棄しない</li><li><strong>回避</strong>: 攻撃されると命令を放棄して逃走する</li></ul></li><li>陸戦ユニットには<strong>オート戦闘</strong>ボタンもあり、戦闘を自動処理できます。</li></ul><hr><h2 id="陸軍" tabindex="-1">陸軍 <a class="header-anchor" href="#陸軍" aria-label="Permalink to &quot;陸軍&quot;">​</a></h2><h3 id="兵舎と徴募" tabindex="-1">兵舎と徴募 <a class="header-anchor" href="#兵舎と徴募" aria-label="Permalink to &quot;兵舎と徴募&quot;">​</a></h3><ul><li>陸戦ユニットは<strong>兵舎</strong>で徴募します。兵舎は人口を一定以上に増やし、労働力と軍隊の両方を維持できるようになると解禁されます。</li><li>キャンペーンでは<strong>第2幕</strong>で兵舎と防御施設が導入されます。</li><li>最初に徴募できる基本ユニットは<strong>歩兵（アウクシリア）<strong>と</strong>弓兵</strong>です。それ以上のユニットタイプは研究と信仰の上昇で解禁されます。</li></ul><h3 id="ユニットの4分類" tabindex="-1">ユニットの4分類 <a class="header-anchor" href="#ユニットの4分類" aria-label="Permalink to &quot;ユニットの4分類&quot;">​</a></h3><p>陸戦ユニットは4タイプに分かれ、それぞれ専用の徴募建物を持ちます:</p><table tabindex="0"><thead><tr><th>分類</th><th>代表ユニット</th><th>備考</th></tr></thead><tbody><tr><td>歩兵</td><td>アウクシリア / ローマ軍団兵 / ムルミロ剣闘士</td><td>武器が必要。軍団兵には高価な防具の生産が必要</td></tr><tr><td>遠隔</td><td>弓兵 / 投石兵</td><td>距離を保って戦う</td></tr><tr><td>騎兵</td><td>騎兵隊 / 近衛騎兵</td><td>高い機動性</td></tr><tr><td>攻城兵器</td><td>バリスタ / カタパルト</td><td>部隊攻撃 / 建物・防御施設</td></tr></tbody></table><ul><li><strong>ローマ軍団兵</strong>は高性能ユニットで、スキルツリーから解禁されます。生産に高価な防具が必要です。</li><li><strong>騎兵</strong>は市民スキルツリーの「エポナの蹄音」研究を完了すると解禁されます。この研究は動物系生産チェーン・物流速度の強化や農業サイロの解禁も伴います。</li></ul><h3 id="兵装と資源・維持コスト" tabindex="-1">兵装と資源・維持コスト <a class="header-anchor" href="#兵装と資源・維持コスト" aria-label="Permalink to &quot;兵装と資源・維持コスト&quot;">​</a></h3><ul><li>歩兵には武器が必要です。</li><li>すべてのユニットは徴兵に資源と資金が必要で、さらに<strong>維持費</strong>と<strong>維持に必要な労働力</strong>がかかります。軍事力が人口・経済の安定に直結する設計です。</li><li>部隊を徴兵すると<strong>労働力が減少します</strong>。徴兵と並行して住宅を建設・アップグレードし続けるとよいでしょう。</li><li>防衛時も攻撃時も、近接と遠隔を混在させたバランスの良い編成が望ましいです。</li></ul><blockquote><p><strong>Tips</strong>: 他の島との間で兵の労働力移動ができます。部隊を選択して「労働力」→他の島を指定すると移動できます。人口に余裕のある島から移動させると、労働力を圧迫せず徴兵できます。</p></blockquote><hr><h2 id="海軍" tabindex="-1">海軍 <a class="header-anchor" href="#海軍" aria-label="Permalink to &quot;海軍&quot;">​</a></h2><h3 id="造船所と艦船建造" tabindex="-1">造船所と艦船建造 <a class="header-anchor" href="#造船所と艦船建造" aria-label="Permalink to &quot;造船所と艦船建造&quot;">​</a></h3><ul><li>艦船は<strong>造船所</strong>で建造します。造船所は港湾建設タブから建てられ、十分な住民（プレブス・リベルトゥス、あるいは特定の都市ステータス到達）が必要です。</li><li>建造前に<strong>ロープ</strong>と<strong>帆</strong>の生産が必要です。建造には資金と資源を要します。</li><li>造船所では2系統を建造できます: <ul><li><strong>民間船</strong>: 物資・市民の輸送用</li><li><strong>軍船</strong>: 海上での戦闘用</li></ul></li></ul><h3 id="艦船タイプ-小型→大型" tabindex="-1">艦船タイプ（小型→大型） <a class="header-anchor" href="#艦船タイプ-小型→大型" aria-label="Permalink to &quot;艦船タイプ（小型→大型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>艦船</th><th>解禁条件</th></tr></thead><tbody><tr><td>ペンテコンター</td><td>基本</td></tr><tr><td>トライリーメ（三段櫂船）</td><td>研究で解禁</td></tr><tr><td>クィンクェレメ（五段櫂船）</td><td>研究で解禁</td></tr></tbody></table><ul><li>大型艦ほど搭載できるモジュールが多く、貨物や陸戦部隊の積載量も増えます。</li><li>同盟相手から購入する艦船は高価で、改造不可です。</li></ul><h3 id="艦船モジュール-武装・性能" tabindex="-1">艦船モジュール（武装・性能） <a class="header-anchor" href="#艦船モジュール-武装・性能" aria-label="Permalink to &quot;艦船モジュール（武装・性能）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>モジュール</th><th>機能</th></tr></thead><tbody><tr><td>船上弓兵</td><td>射程は短いが攻撃スピードが速い。船同士の戦闘に必須。追加の人手を要する</td></tr><tr><td>船上バリスタ</td><td>中距離戦闘に強い。陸・海両用の攻撃に有用。追加の乗員が必要</td></tr><tr><td>船上カタパルト</td><td>低速・低命中だが高威力。建物の攻撃にベスト</td></tr><tr><td>マスト</td><td>追い風時の最大速度を上げる</td></tr><tr><td>オール</td><td>機動力を上げ風への依存を減らす（労働力コスト増）</td></tr><tr><td>船体装甲</td><td>被ダメージへの耐久力を上げる。装備に防具が必要</td></tr></tbody></table><ul><li>攻撃モジュール3種（船上弓兵・バリスタ・カタパルト）は射程・命中精度・連射速度・威力が異なり、状況によって使い分けます。 <ul><li>船上弓兵: 射程が限られ、<strong>防御施設を破壊できない</strong></li><li>船上カタパルト: 低速・不正確だが高威力</li></ul></li><li>モジュール構成は自動保存され、別構成にするには手動でリセットが必要です。</li></ul><h3 id="艦隊運用" tabindex="-1">艦隊運用 <a class="header-anchor" href="#艦隊運用" aria-label="Permalink to &quot;艦隊運用&quot;">​</a></h3><ul><li>1隻ずつ選択するか、ドラッグで艦隊全体を一括操作できます。</li><li>艦隊は敵艦との戦闘・他島との交易・陸戦部隊を運んで敵の総督のヴィラを攻撃する、といった用途に使えます。</li></ul><hr><h2 id="防衛" tabindex="-1">防衛 <a class="header-anchor" href="#防衛" aria-label="Permalink to &quot;防衛&quot;">​</a></h2><ul><li>防御施設には<strong>木柵</strong>・<strong>石壁</strong>・**防御塔（射手塔）**などがあります。 <ul><li>耐久力は木製 <strong>&lt;</strong> 石造り。</li><li>石壁は砲兵でなければ破壊できません。</li><li>防御塔（特に射手塔）は侵攻してくる敵に反撃し、大きなダメージを与える防衛の要です。</li></ul></li><li><strong>敵はビーチ（砂浜）からのみ侵攻してきます</strong>。そのため壁は砂浜のアクセス地点に集中させるのが効率的です（島全周を囲む必要はありません）。 <ul><li>戦術例: 全ビーチを壁で塞ぎ、1か所だけ開けて誘い込む。門を使わず一点に敵を誘導して集中砲火する。</li></ul></li><li><strong>軍事系の研究</strong>で: <ul><li>壁の建設コストと維持費を下げられます。</li><li><strong>水上に防御塔を建てられる</strong>技術が解禁され、沿岸防衛を拡張できます。</li></ul></li><li><strong>総督のヴィラ</strong>は新機能を解禁し、部隊を駐留させられる重要建物です。木製壁と射手塔で守ることが推奨されます。</li></ul><hr><h2 id="いつ戦うか・交易するか" tabindex="-1">いつ戦うか・交易するか <a class="header-anchor" href="#いつ戦うか・交易するか" aria-label="Permalink to &quot;いつ戦うか・交易するか&quot;">​</a></h2><ul><li>戦闘は資源・資金・労働力を消費し、維持費も継続的にかかるため、軍備は経済・人口の安定とのバランスが重要です。</li><li>むやみな拡張より、相性編成（近接＋遠隔＋騎兵＋砲兵）と防衛施設の効率配置が鍵です。</li><li>交易・外交で解決できる局面と、軍事制圧すべき局面の見極めが推奨されます。</li></ul>',31))])}const c=e(a,[["render",d]]);export{b as __pageData,c as default};
